// Preemptive Basic Auth
given().
    auth().preemptive().basic("admin", "secret").
when().
    get("/secure/data").
then().
    statusCode(200);

// Bearer Token Auth
String token = "eyJhbGciOiJIUzI1...";
given().
    header("Authorization", "Bearer " + token).
when().
    get("/profile").
then().
    statusCode(200);
